mapper.select:
SELECT * FROM workshop
JOIN program USING(workshop_id)
WHERE program_id = #{programId}

mapper.update:
UPDATE workshop
SET profile_img = #{profileImg}
WHERE workshop_id = #{workshopId}

UPDATE workshop
SET
active = #{active}
WHERE workshop_id = #{workshopId}
AND owner_id = #{ownerId}

UPDATE workshop
SET approved = #{approved},
    active = #{active}
WHERE workshop_id = #{targetId}

mapper.select:
SELECT w.workshop_id, w.owner_id, w.name, w.status, w.approved, w.active, w.created_at, u.user_id, u.name AS user_name, u.email FROM workshop w LEFT JOIN user u ON w.owner_id = u.user_id
WHERE 1=1
AND approved = #{filter}
AND (w.name LIKE CONCAT('%', #{keyword}, '%') OR u.name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY
${sortBy} ${sortDir}
w.created_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM workshop w LEFT JOIN user u ON w.owner_id = u.user_id WHERE 1=1
AND approved = #{filter}
AND (w.name LIKE CONCAT('%', #{keyword}, '%') OR u.name LIKE CONCAT('%', #{keyword}, '%'))
